#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = vec2(vUv.x-0.5+q19,vUv.y-0.5);//*uAspect.xy;

dx = texture(sampler_main,vUv+ofs[0]) - texture(sampler_main,vUv-ofs[0]);
dy = texture(sampler_main,vUv+ofs[1]) - texture(sampler_main,vUv-ofs[1]);
zz = vec2(dx.b,dy.b);

//clouds
zv = uTime*.06 ;
zv = uTime*.08+ .0*GetPixel(vUv); //##
uv2 = 3*uv1+ vec2(0.02*uTime,-.05*uTime);

n1 = texture3D(sampler_noisevol_hq,vec3 (uv2.x,uv2.y,zv)).b;
n2 = texture3D(sampler_noisevol_hq,vec3 (uv2.x*2,uv2.y*2,zv*2)).b;
n3 = texture3D(sampler_noisevol_hq,vec3 (uv2.x*4,uv2.y*4,zv*3)).b;
n4 = texture3D(sampler_noisevol_hq,vec3 (uv2.x*8,uv2.y*8,zv*7)).b;
noise = n1 + n2/2 + n3/4 + n4/8 -1;
noise = pow(noise,1);
uv2 = uv1+noise*.1;

//*******************************
ret1 = cloud(uv2);
float k1 = .1;
ret = ret1*k1/2 + GetPixel(vUv-.02*zz)*(1-k1)-.01;

//ret = 0;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
mat2 ang1 = mat2 (_qb);
vUv = multiply((vUv-.5),ang1)*.7*uAspect.xy+.5+vec2(q15,q16);

vec2 center = vec2 (.5,q11+.6+q12*(sin(vUv.x*6+trel)*cos(vUv.y*8+uTime*.6)));
rain = texture(sampler_noise_lq,vec2(vUv.x*4,vUv.y)*.2-uTime);
rain += texture(sampler_noise_lq,vec2(vUv.x*4,vUv.y)*.5-uTime);
rain *= 1*clamp01(q20/2-abs(sin(uv0.x/4-uTime/4)));


uv1 = (vUv-center+rain*.01);

float noise = texture3D(sampler_noisevol_hq,vec3(uv1.y,uv1.x*2,uTime*.2))
              *(.5-abs(uv1.y));
uv1 += noise*.05;
mask = clamp01(128*uv1.y);
z = .4/(uv1.y);
rs0.x = uv1.x * z; rs0.y = z ;
rs = vec2 (rs0.x+uTime/4, rs0.y+uTime*4)*mask;
water = texture(sampler_noise_hq,rs) + texture(sampler_noise_hq,rs/4-uTime/8);
//water = pow(water/2,2);
water -= 1 ;
uv_sky = vec2(vUv.x,vUv.y);
uv_wat = vec2(uv1.x+.5,abs(.5-uv1.y))-.2*water;


ret1 = GetPixel(uv_sky+rain*.0)*(1-mask) + //Himmel
GetPixel(uv_wat)*mask*pow(1/z,.2)*(2-rand_preset.y) + //Wasser
(.25+rand_preset.y)*
(1+rand_preset.x*water)*mask/z*vec3(0,.1,.1); //Leuchten Wasser

ret1 += .06*rain*(1);
ret = 1-exp(-pow(ret1,1.5)*8*(1+q23*4));

  fragColor = ret;
}
